        const __m256d qbr=_mm256_fnmadd_pd(cC,d1i,_mm256_mul_pd(cB,d2i)),qbi=_mm256_fnmadd_pd(cC,d1r,_mm256_mul_pd(cB,d2r));
        const __m256d Y1r = _mm256_sub_pd(p1r,qar), Y1i = _mm256_add_pd(p1i,qai);
